const item = $input.first().json.data.items[0];
const cols = {};
item.column_values.forEach(c => { cols[c.id] = c.text; });
const asset = item.assets?.[0];

return [{
  json: {
    monday_item_id:      item.id,
    titulo:              item.name,
    tipo:                (cols.tipo_comunicacion || '').toLowerCase().trim(),
    modo_envio:          (cols.modo_envio || '').toUpperCase().trim(),
    empresa:             (cols.text_empresa || '').toUpperCase().trim(),
    segmento:            cols.text_segmento || '',
    id_encuesta_maestro: cols.text_encuesta_id || '',
    flow_id:             cols.text_flow_id || '',
    template_name:       cols.text_template || '',
    texto_cuerpo:        cols.long_text_cuerpo || '',
    url_destino:         cols.text_url || '',
    text_media_id:       cols.text_media_id || '',
    public_url_imagen:   asset?.public_url || null,
    asset_id:            asset?.id || null
  }
}];

// Unifica el media_id: viene del upload o del campo monday
const campos = $('Code: Extraer campos').item.json;
const uploadResult = $('HTTP: Subir imagen a Meta (enc)').item?.json;
const wa_media_id = uploadResult?.id || campos.text_media_id || '';

return [{
  json: {
    ...campos,
    wa_media_id,
    id_encuesta_bigint: $('PG: Validar encuesta').item.json.id_encuesta,
    version_num: $('PG: Versión activa').item.json.version_num,
    phone_number_id: $('PG: Empresa phone_number_id').item.json.phone_number_id
  }
}];

// Consolida el contexto para el loop de envíos
const campos = $('Code: Merge media_id (enc)').item.json;
const id_campana = $('PG: Upsert campana').item.json.id;

return [{
  json: {
    ...campos,
    id_campana
  }
}];

// EQUIPO: teléfonos internos — MODIFICAR CON LOS REALES
const ctx = $('Code: Prep contexto enc').item.json;
const equipo = [
  { telefono_wa: '34600000001', razon_social: 'Equipo WA 1', codigo_isi: null },
  { telefono_wa: '34600000002', razon_social: 'Equipo WA 2', codigo_isi: null }
];
return equipo.map(c => ({ json: { ...ctx, ...c } }));

// Modo REAL_MANUAL: descargar CSV de monday y parsear
// El asset_id viene de 'Code: Extraer campos'
const ctx = $('Code: Prep contexto enc').item.json;

// Aquí se usa el nodo HTTP para descargar el CSV (ver notas)
// Por ahora retornamos el contexto para que el siguiente nodo HTTP lo descargue
return [{ json: { ...ctx, _needs_csv_download: true } }];

// Agrega el contexto de campaña a cada contacto
// Este nodo recibe items de cualquiera de los nodos de contactos anteriores
const ctx = $('Code: Prep contexto enc').item.json;

return $input.all().map(item => ({
  json: {
    telefono_wa:  item.json.telefono_wa,
    codigo_isi:   item.json.codigo_isi || null,
    razon_social: item.json.razon_social || null,
    id_campana:   ctx.id_campana,
    monday_item_id: ctx.monday_item_id,
    template_name:  ctx.template_name,
    flow_id:        ctx.flow_id,
    wa_media_id:    ctx.wa_media_id,
    phone_number_id: ctx.phone_number_id,
    texto_cuerpo:   ctx.texto_cuerpo,
    id_encuesta_maestro: ctx.id_encuesta_maestro,
    empresa:        ctx.empresa
  }
}));

