={{ JSON.stringify({
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: $('Code: Merge contactos + ctx').item.json.telefono_wa,
  type: 'template',
  template: {
    name: $('Code: Merge contactos + ctx').item.json.template_name,
    language: { code: 'es' },
    components: [
      {
        type: 'header',
        parameters: [{ type: 'image', image: { id: $('Code: Merge contactos + ctx').item.json.wa_media_id } }]
      },
      {
        type: 'body',
        parameters: [
          { type: 'text', text: $('Code: Merge contactos + ctx').item.json.razon_social || 'Cliente' },
          { type: 'text', text: $('Code: Merge contactos + ctx').item.json.texto_cuerpo || '' }
        ]
      },
      {
        type: 'button',
        sub_type: 'flow',
        index: '0',
        parameters: [{
          type: 'action',
          action: {
            flow_token: $json.wa_flow_token,
            flow_action_data: {
              id_encuesta_maestro: $('Code: Merge contactos + ctx').item.json.id_encuesta_maestro
            }
          }
        }]
      }
    ]
  }
}) }}

