const campos = $('Code: Extraer campos').item.json;
const uploadResult = $('HTTP: Subir imagen a Meta (notif)').item?.json;
const wa_media_id = uploadResult?.id || campos.text_media_id || '';
const phone_number_id = $('PG: Empresa phone_number_id (notif)').item.json.phone_number_id;

return [{ json: { ...campos, wa_media_id, phone_number_id } }];

const ctx = $('Code: Merge ctx notif').item.json;
const equipo = [
  { telefono_wa: '34600000001', razon_social: 'Equipo WA 1' },
  { telefono_wa: '34600000002', razon_social: 'Equipo WA 2' }
];
return equipo.map(c => ({ json: { ...ctx, ...c } }));

const ctx = $('Code: Merge ctx notif').item.json;
return $input.all().map(item => ({
  json: {
    telefono_wa:  item.json.telefono_wa,
    razon_social: item.json.razon_social || null,
    monday_item_id: ctx.monday_item_id,
    template_name:  ctx.template_name,
    wa_media_id:    ctx.wa_media_id,
    phone_number_id: ctx.phone_number_id,
    texto_cuerpo:   ctx.texto_cuerpo,
    url_destino:    ctx.url_destino
  }
}));

